    /*
     *用户登录
     *author：刘飞华
     *date：2025/01/08 13:51:14
     */
    pub async fn login(depot: &mut Depot, req: &mut Request) -> AppResult<String> {
        let item = req.parse_json::<UserLoginReq>().await?;
        info!("user login params: {:?}", &item);

        let user_agent = req.header::<&str>("user-agent").unwrap_or_default();
        info!("user agent: {:?}", user_agent);
        let agent = UserAgentUtil::new(user_agent);

        let rb = &mut RB.clone();
        let user_result = User::select_by_account(rb, &item.account).await?;
        info!("query user by account: {:?}", user_result);

        match user_result.get(0) {
            None => {
                Self::add_login_log(item.account, 0, "用户不存在", agent).await;
                Err(AppError::BusinessError("用户不存在"))
            }
            Some(user) => {
                let mut s_user = user.clone();
                let id = user.id.unwrap_or_default();
                let username = &s_user.user_name;
                let password = &user.password;

                if password.ne(&item.password) {
                    Self::add_login_log(item.account, 0, "密码不正确", agent).await;
                    return Err(AppError::BusinessError("密码不正确"));
                }

                let (btn_menu, is_super) = Self::query_btn_menu(&id).await;

                if btn_menu.len() == 0 {
                    Self::add_login_log(item.account, 0, "用户没有分配角色或者菜单,不能登录", agent).await;
                    return Err(AppError::BusinessError("用户没有分配角色或者菜单,不能登录"));
                }

                let secret = depot.get::<String>("secret").map_err(|_| AppError::BusinessError("获取jwt密钥异常"))?;
                let token = JwtToken::new(id, &username).create_token(secret)?;

                let pool = depot.get::<deadpool_redis::Pool>("pool").map_err(|_| AppError::BusinessError("获取redis连接池异常"))?;
                let mut conn = pool.get().await.map_err(|_| AppError::BusinessError("获取redis连接异常"))?;
                let key = format!("salvo:admin:user:info:{:?}", s_user.id.unwrap_or_default());
                deadpool_redis::redis::cmd("HSET")
                    .arg(&key)
                    .arg(&"permissions")
                    .arg(&btn_menu.join(","))
                    .arg(&"user_name")
                    .arg(&username)
                    .arg(&"is_admin")
                    .arg(&is_super)
                    .arg(&"token")
                    .arg(&token)
                    .arg(&"last_login")
                    .arg(&Local::now().format("%Y-%m-%d %H:%M:%S").to_string())
                    .query_async::<()>(&mut conn)
                    .await?;

                Self::add_login_log(item.account, 1, "登录成功", agent.clone()).await;
                s_user.login_os = agent.os;
                s_user.login_browser = agent.browser;
                s_user.login_date = Some(DateTime::now());

                User::update_by_map(rb, &s_user, value! {"id": s_user.id}).await?;
                ok_result_data(token)
            }
        }
    }

    /*
     *添加登录日志
     *author：刘飞华
     *date：2025/01/08 13:51:14
     */
    async fn add_login_log(name: String, status: i8, msg: &str, agent: UserAgentUtil) {
        let sys_login_log = LoginLog {
            id: None,                             //访问ID
            login_name: name,                     //登录账号
            ipaddr: "todo".to_string(),           //登录IP地址
            login_location: "todo".to_string(),   //登录地点
            platform: agent.platform,             //平台信息
            browser: agent.browser,               //浏览器类型
            version: agent.version,               //浏览器版本
            os: agent.os,                         //操作系统
            arch: agent.arch,                     //体系结构信息
            engine: agent.engine,                 //渲染引擎信息
            engine_details: agent.engine_details, //渲染引擎详细信息
            extra: agent.extra,                   //其他信息（可选）
            status,                               //登录状态(0:失败,1:成功)
            msg: msg.to_string(),                 //提示消息
            login_time: None,                     //访问时间
        };

        match LoginLog::insert(&mut RB.clone(), &sys_login_log).await {
            Ok(_u) => info!("add_login_log success: {:?}", sys_login_log),
            Err(err) => error!("add_login_log error params: {:?}, error message: {:?}", sys_login_log, err),
        }
    }

    /*
     *查询按钮权限
     *author：刘飞华
     *date：2025/01/08 13:51:14
     */
    async fn query_btn_menu(id: &i64) -> (Vec<String>, bool) {
        let mut btn_menu: Vec<String> = Vec::new();
        let rb = &mut RB.clone();

        if UserRole::is_admin(rb, id).await.unwrap_or_default() > 0 {
            for x in Menu::select_by_map(rb, value! {"api_url !=":""}).await.unwrap_or_default() {
                btn_menu.push(x.api_url.unwrap_or_default());
            }
            info!("The current user is a super administrator");
            (btn_menu, true)
        } else {
            let sql_str = "select distinct u.api_url from sys_user_role t left join sys_role usr on t.role_id = usr.id left join sys_role_menu srm on usr.id = srm.role_id left join sys_menu u on srm.menu_id = u.id where u.api_url !='' and t.user_id = ?";
            let btn_menu_map = rb.exec_decode::<Vec<HashMap<String, String>>>(sql_str, vec![value!(id)]).await.unwrap_or_default();
            for x in btn_menu_map {
                if let Some(api_url) = x.get("api_url") {
                    btn_menu.push(api_url.to_string());
                }
            }
            info!("The current user is not a super administrator");
            (btn_menu, false)
        }
    }

    /*
     *查询用户角色
     *author：刘飞华
     *date：2025/01/08 13:51:14
     */
    pub async fn query_user_role(item: QueryUserRoleReq) -> AppResult<QueryUserRoleResp> {
        let rb = &mut RB.clone();
        let mut user_role_ids: Vec<i64> = Vec::new();

        let user_id = item.user_id;
        for x in UserRole::select_by_map(rb, value! {"user_id": user_id}).await? {
            user_role_ids.push(x.role_id);
        }

        let sys_role_list = Role::select_by_map(rb, value! {}).await.map(|x| x.into_iter().map(|x| x.into()).collect::<Vec<RoleResp>>())?;

        ok_result_data(QueryUserRoleResp { sys_role_list, user_role_ids })
    }

    /*
     *更新用户与角色的关联
     *author：刘飞华
     *date：2025/01/08 13:51:14
     */
    pub async fn update_user_role(item: UpdateUserRoleReq) -> AppResult<String> {
        let user_id = item.user_id;

        let rb = &mut RB.clone();

        if UserRole::is_admin(rb, &user_id).await? > 0 {
            return Err(AppError::BusinessError("不能修改超级管理员的角色"));
        }

        UserRole::delete_by_map(rb, value! {"user_id": user_id}).await?;

        let list: Vec<UserRole> = item.role_ids.into_iter().map(|role_id| UserRole { id: None, role_id, user_id }).collect();

        UserRole::insert_batch(rb, &list, list.len() as u64).await.map(|_| ok_result())?
    }

    /*
     *查询用户菜单
     *author：刘飞华
     *date：2025/01/08 13:51:14
     */
    pub async fn query_user_menu(user_id: i64) -> AppResult<QueryUserMenuResp> {
        //根据id查询用户
        let rb = &mut RB.clone();

        match User::select_by_id(rb, &user_id).await? {
            None => Err(AppError::BusinessError("用户不存在")),
            Some(user) => {
                let sys_menu_list: Vec<Menu>;

                if UserRole::is_admin(rb, &user_id).await? > 0 {
                    info!("The current user is a super administrator");
                    sys_menu_list = Menu::select_by_map(rb, value! {}).await?;
                } else {
                    info!("The current user is not a super administrator");
                    let sql_str = "select u.* from sys_user_role t left join sys_role usr on t.role_id = usr.id left join sys_role_menu srm on usr.id = srm.role_id left join sys_menu u on srm.menu_id = u.id where t.user_id = ?";
                    sys_menu_list = RB.exec_decode(sql_str, vec![value!(user.id)]).await?;
                }

                let mut sys_menu: Vec<MenuList> = Vec::new();
                let mut btn_menu: Vec<String> = Vec::new();
                let mut sys_menu_ids: HashSet<i64> = HashSet::new();

                for x in sys_menu_list {
                    if x.menu_type != 3 {
                        sys_menu_ids.insert(x.id.unwrap_or_default());
                        sys_menu_ids.insert(x.parent_id.unwrap_or_default());
                    }
                    btn_menu.push(x.api_url.unwrap_or_default());
                }

                let mut menu_ids = Vec::new();
                for id in sys_menu_ids {
                    menu_ids.push(id)
                }
                for menu in Menu::select_by_map(rb, value!("id", &menu_ids, "status", 1)).await? {
                    let api_url = menu.api_url.unwrap_or_default();
                    sys_menu.push(MenuList {
                        id: menu.id,
                        parent_id: menu.parent_id,
                        name: menu.menu_name,
                        icon: menu.menu_icon.unwrap_or_default(),
                        api_url: api_url.clone(),
                        menu_type: menu.menu_type,
                        path: menu.menu_url.unwrap_or_default(),
                    });
                    btn_menu.push(api_url);
                }

                let data = QueryUserMenuResp {
                    sys_menu,
                    btn_menu: btn_menu.into_iter().filter(|x| x != "").collect(),
                    avatar: "https://gw.alipayobjects.com/zos/antfincdn/XAosXuNZyF/BiazfanxmamNRoxxVxka.png".to_string(),
                    name: user.user_name,
                };
                ok_result_data(data)
            }
        }
    }
